function SliderDemo() {
  const [value, setValue] = useState(50);

  const handleKeyDown = (e) => {
    if (e.key === 'ArrowRight' || e.key === 'ArrowUp') setValue(v => Math.min(100, v + 1));
    if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') setValue(v => Math.max(0, v - 1));
    if (e.key === 'Home') setValue(0);
    if (e.key === 'End') setValue(100);
    if (e.key === 'PageUp') setValue(v => Math.min(100, v + 10));
    if (e.key === 'PageDown') setValue(v => Math.max(0, v - 10));
  };

  return (
    <div>
      <label id="volume-label">볼륨: {value}%</label>
      <div
        role="slider"
        aria-valuenow={value}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-labelledby="volume-label"
        aria-valuetext={`${value}퍼센트`}
        tabIndex={0}
        onKeyDown={handleKeyDown}
        style={{ width: '200px', height: '8px', background: '#ddd', position: 'relative', cursor: 'pointer' }}
      >
        <div
          style={{
            position: 'absolute',
            left: `${value}%`,
            top: '50%',
            transform: 'translate(-50%, -50%)',
            width: '20px',
            height: '20px',
            background: '#1976d2',
            borderRadius: '50%'
          }}
        />
      </div>
    </div>
  );
}
